/**
 * SQLite Migration Runner — M168 Phase 2 (#1912)
 *
 * Tracks schema version via PRAGMA user_version. Each migration file is
 * named NNN-<slug>.sql where NNN starts at 001 and increments by 1.
 *
 * The runner reads the current user_version, executes any migration files
 * with a higher prefix in ascending order, then trusts each migration file
 * to update PRAGMA user_version to the new value as its first statement.
 *
 * Idempotent: re-running with no new files is a no-op.
 */

import type { DatabaseSync } from 'node:sqlite';
import { readFileSync, readdirSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const MIGRATIONS_DIR = __dirname;

/** A pending migration discovered on disk. */
interface MigrationFile {
  version: number;
  filename: string;
  sql: string;
}

/**
 * Read all migration files from the migrations directory, sorted by version.
 * File naming: NNN-<slug>.sql (e.g. 001-initial.sql).
 */
function listMigrations(): MigrationFile[] {
  const entries = readdirSync(MIGRATIONS_DIR).filter(f => /^\d{3}-.+\.sql$/.test(f));
  const files: MigrationFile[] = [];
  for (const filename of entries) {
    const m = filename.match(/^(\d{3})-/);
    if (!m) continue;
    const version = Number.parseInt(m[1] ?? '0', 10);
    const sql = readFileSync(join(MIGRATIONS_DIR, filename), 'utf8');
    files.push({ version, filename, sql });
  }
  files.sort((a, b) => a.version - b.version);
  return files;
}

/**
 * Apply any pending migrations to the open DB. Returns the count of applied
 * migrations. No-op if the DB is already at the latest version.
 */
export function runMigrations(db: DatabaseSync): number {
  // node:sqlite has no .pragma() — read the scalar via a prepared statement.
  const row = db.prepare('PRAGMA user_version').get() as { user_version?: number } | undefined;
  const current = row?.user_version ?? 0;
  const pending = listMigrations().filter(m => m.version > current);
  if (pending.length === 0) return 0;
  for (const m of pending) {
    // Each migration runs in its own implicit transaction (exec wraps).
    db.exec(m.sql);
  }
  return pending.length;
}

